const express = require('express');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 3000;

// Load plugins from configuration or environment variables
function loadPlugins() {
    const pluginConfig = process.env.PLUGINS || 'plugins.json';
    try {
        const config = JSON.parse(fs.readFileSync(pluginConfig, 'utf8'));
        return config.plugins.map(plugin => require(path.resolve(__dirname, plugin.path)));
    } catch (error) {
        console.error('Error loading plugins:', error);
        return [];
    }
}

const plugins = loadPlugins();

// Middleware to apply plugins
function applyPlugins(req, res, next) {
    let index = 0;
    function runPlugin() {
        if (index < plugins.length) {
            const plugin = plugins[index++];
            try {
                plugin(req, res, runPlugin);
            } catch (error) {
                console.error('Error in plugin:', error);
                next(error);
            }
        } else {
            next();
        }
    }
    runPlugin();
}

// Example request modification plugin
function modifyRequest(req, res, next) {
    req.customHeader = 'Modified by Plugin';
    next();
}

// Example response modification plugin
function modifyResponse(req, res, next) {
    res.on('finish', () => {
        console.log('Response status:', res.statusCode);
    });
    next();
}

// Add plugins to the middleware stack
app.use(applyPlugins);

// Example route
app.get('/', (req, res) => {
    res.send('Hello World!');
});

// Start server
app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}/`);
});